  (1, 'Daily Revenue Summary', 2, 1, 'SELECT date_key, SUM(revenue) as total FROM sales.daily GROUP BY date_key', 'primary_key', ARRAY['date_key'], 'system', 'system'),
  (2, 'Product Performance', 2, 1, 'SELECT product_id, SUM(units_sold) as total FROM sales.performance GROUP BY product_id', 'primary_key', ARRAY['product_id'], 'system', 'system'),
  (3, 'Monthly Financials', 2, 1, 'SELECT month_key, SUM(amount) as total FROM finance.monthly GROUP BY month_key', 'primary_key', ARRAY['month_key'], 'system', 'system'),
  
