  (6, 'Employee Headcount', 4, 3, 'SELECT department, COUNT(*) FROM hr.headcount GROUP BY department', 'except_all', ARRAY[]::TEXT[], 'system', 'system');

SELECT setval('control.compare_queries_id_seq', (SELECT MAX(id) FROM control.compare_queries));

